SELECT *
FROM public_data_raw


        AND dpsl_mtd_cd = #{request.dpslMtdCd}


        AND nmrd_adrs LIKE CONCAT('%', #{request.sido}, '%')


ORDER BY pbct_begn_dtm DESC
LIMIT #{request.numOfRows} OFFSET #{(request.pageNo-1) * request.numOfRows}

